DROP TABLE IF EXISTS `file_metadata`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!50503 SET character_set_client = utf8mb4 */;
CREATE TABLE `file_metadata` (
  `id` varchar(36) COLLATE utf8mb4_unicode_ci NOT NULL,
  `r2_key` varchar(500) COLLATE utf8mb4_unicode_ci NOT NULL,
  `conversation_id` varchar(100) COLLATE utf8mb4_unicode_ci NOT NULL,
  `user_id` int NOT NULL,
  `original_name` varchar(255) COLLATE utf8mb4_unicode_ci NOT NULL,
  `file_type` varchar(50) COLLATE utf8mb4_unicode_ci DEFAULT 'other',
  `mime_type` varchar(100) COLLATE utf8mb4_unicode_ci DEFAULT '',
  `file_size` bigint DEFAULT '0',
  `uploaded_at` timestamp NULL DEFAULT CURRENT_TIMESTAMP,
  `origin_message_id` int DEFAULT NULL,
  PRIMARY KEY (`id`),
  UNIQUE KEY `r2_key` (`r2_key`),
  KEY `idx_fm_conversation_id` (`conversation_id`),
  KEY `idx_fm_user_id` (`user_id`),
  KEY `idx_fm_uploaded_at` (`uploaded_at`),
  CONSTRAINT `file_metadata_ibfk_1` FOREIGN KEY (`user_id`) REFERENCES `users` (`id`) ON DELETE CASCADE
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;
