DROP TABLE IF EXISTS `user_settings`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!50503 SET character_set_client = utf8mb4 */;
CREATE TABLE `user_settings` (
  `id` int NOT NULL AUTO_INCREMENT,
  `user_id` int NOT NULL,
  `theme` varchar(20) COLLATE utf8mb4_unicode_ci DEFAULT 'system',
  `compact_mode` tinyint(1) DEFAULT '0',
  `message_density` varchar(20) COLLATE utf8mb4_unicode_ci DEFAULT 'comfortable',
  `sidebar_collapsed` tinyint(1) DEFAULT '0',
  `notifications_enabled` tinyint(1) DEFAULT '1',
  `sound_enabled` tinyint(1) DEFAULT '1',
  `notification_sound` varchar(50) COLLATE utf8mb4_unicode_ci DEFAULT 'default',
  `desktop_notifications` tinyint(1) DEFAULT '1',
  `mute_all` tinyint(1) DEFAULT '0',
  `online_status_visible` tinyint(1) DEFAULT '1',
  `typing_indicator` tinyint(1) DEFAULT '1',
  `read_receipts` tinyint(1) DEFAULT '1',
  `last_seen_visible` tinyint(1) DEFAULT '1',
  `auto_play_videos` tinyint(1) DEFAULT '0',
  `auto_play_gifs` tinyint(1) DEFAULT '1',
  `preview_links` tinyint(1) DEFAULT '1',
  `date_format` varchar(10) COLLATE utf8mb4_unicode_ci DEFAULT '12h',
  `language` varchar(10) COLLATE utf8mb4_unicode_ci DEFAULT 'en',
  `timezone` varchar(50) COLLATE utf8mb4_unicode_ci DEFAULT 'UTC',
  `debug_mode` tinyint(1) DEFAULT '0',
  `updated_at` timestamp NULL DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP,
  PRIMARY KEY (`id`),
  UNIQUE KEY `user_id` (`user_id`),
  CONSTRAINT `user_settings_ibfk_1` FOREIGN KEY (`user_id`) REFERENCES `users` (`id`) ON DELETE CASCADE
) ENGINE=InnoDB AUTO_INCREMENT=32 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;
